const staticData = $getWorkflowStaticData('global');
if (!staticData.sentLinks) staticData.sentLinks = {};

const maxAgeMs = 100 * 60 * 60 * 1000;
const now = Date.now();
const seen = new Set();
const articles = [];

for (const item of $input.all()) {
  if (item.json.error) continue;
  const link = item.json.link || item.json.guid || '';
  if (!link) continue;
  if (seen.has(link)) continue;
  seen.add(link);

  const title = item.json.title || '';
  if (title.includes('\uFFFD')) continue;

  const pubDate = item.json.pubDate || item.json.isoDate || item.json.date || '';
  if (pubDate) {
    const ts = new Date(pubDate).getTime();
    if (!isNaN(ts) && (now - ts) > maxAgeMs) continue;
  }

  if (staticData.sentLinks[link]) continue;

  articles.push({
    idx: articles.length,
    title,
    link,
    pubDate,
    snippet: (item.json.contentSnippet || item.json.description || '').slice(0, 150)
  });
  if (articles.length >= 15) break;
}

if (articles.length === 0) return [];

const articlesText = articles
  .map(a => '[' + a.idx + '] ' + a.title + (a.snippet ? '. ' + a.snippet : ''))
  .join('\n');

return [{ json: { articles, articlesText } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.sentLinks) staticData.sentLinks = {};
if (!staticData.pendingPosts) staticData.pendingPosts = {};
const now = Date.now();

const dsItem = $input.first();
if (!dsItem) return [];

const articles = ($('Фильтр').first()?.json?.articles) || [];
if (articles.length === 0) return [];

let results = [];
try {
  const raw = dsItem.json?.choices?.[0]?.message?.content || '[]';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  results = JSON.parse(cleaned);
  if (!Array.isArray(results)) results = [];
} catch(e) { return []; }

const relevant = [];
for (const ai of results) {
  if (ai.relevant !== true) continue;
  const src = articles[ai.idx];
  if (!src) continue;
  if (staticData.sentLinks[src.link]) continue;

  // Build short_post with source link appended
  let shortPost = ai.short_post || ai.post || '';
  if (shortPost && src.link) {
    shortPost += '\n\n📌 <a href="' + src.link + '">Источник</a>';
  }

  const postId = 'post_' + now + '_' + ai.idx;

  relevant.push({ json: {
    title:        src.title,
    link:         src.link,
    pubDate:      src.pubDate || '',
    short_post:   shortPost,
    image_prompt: ai.image_prompt || '',
    category:     ai.category || 'Металлургия',
    score:        typeof ai.score === 'number' ? ai.score : 5,
    postId:       postId
  }});
}

// Sort by score, take top 3
relevant.sort((a, b) => (b.json.score || 0) - (a.json.score || 0));
const top = relevant.slice(0, 3);

// Mark as sent + save pending posts for callback
for (const item of top) {
  const lnk = item.json.link;
  if (lnk) staticData.sentLinks[lnk] = now;

  // Save post data for callback retrieval
  staticData.pendingPosts[item.json.postId] = {
    short_post: item.json.short_post,
    link: item.json.link,
    title: item.json.title,
    category: item.json.category,
    savedAt: now
  };
}

// Cleanup old sentLinks (7 days)
for (const key of Object.keys(staticData.sentLinks)) {
  if (now - staticData.sentLinks[key] > 7 * 24 * 60 * 60 * 1000) delete staticData.sentLinks[key];
}
// Cleanup old pendingPosts (1 hour — stale callbacks)
for (const key of Object.keys(staticData.pendingPosts)) {
  if (now - (staticData.pendingPosts[key].savedAt || 0) > 60 * 60 * 1000) delete staticData.pendingPosts[key];
}

return top;

const sd = $getWorkflowStaticData('global');
if (!sd.dailyKieCount) sd.dailyKieCount = 0;

const MAX_DAILY_IMAGES = 21;
const item = $input.first().json;
const postId = item.postId || 'unknown';

// Check if daily limit reached
if (sd.dailyKieCount >= MAX_DAILY_IMAGES) {
  return [{json: {postId, skipImage: true, short_post: item.short_post, image_prompt: ''}}];
}

const imagePrompt = item.image_prompt || 'Modern editorial illustration of steel industry and construction';
const cbUrl = 'https://n8n-eremeev-me.ru/webhook/news-image-callback?postId=' + postId;

const kieBody = JSON.stringify({
  model: 'nano-banana-2',
  input: {
    prompt: imagePrompt,
    resolution: '1K',
    aspect_ratio: '16:9'
  },
  callBackUrl: cbUrl
});

return [{json: {postId, kieBody, cbUrl, short_post: item.short_post, image_prompt: imagePrompt, skipImage: false}}];

const sd = $getWorkflowStaticData('global');
if (!sd.pendingPosts) sd.pendingPosts = {};

const input = $input.first().json;
const query = input.query || {};
const body = input.body || {};
const postId = query.postId || '';

// Get saved post data
const postData = sd.pendingPosts[postId];
if (!postData) {
  return [{json: {hasImage: false, skip: true, reason: 'Unknown postId: ' + postId}}];
}

// Extract result URL from KIE callback (all formats)
function extractResultUrl(b) {
  if (b.data && b.data.resultJson) {
    try {
      const rj = typeof b.data.resultJson === 'string' ? JSON.parse(b.data.resultJson) : b.data.resultJson;
      if (rj.resultUrls && Array.isArray(rj.resultUrls) && rj.resultUrls.length > 0) return rj.resultUrls[0];
    } catch(e) {}
  }
  if (b.data && b.data.info && b.data.info.result_urls) {
    const urls = b.data.info.result_urls;
    if (Array.isArray(urls) && urls.length > 0) return urls[0];
  }
  if (b.data && b.data.info && b.data.info.resultUrls) {
    try {
      const urls = typeof b.data.info.resultUrls === 'string' ? JSON.parse(b.data.info.resultUrls) : b.data.info.resultUrls;
      if (Array.isArray(urls) && urls.length > 0) return urls[0];
    } catch(e) {}
  }
  if (b.data && b.data.response && b.data.response.resultUrls) {
    try {
      const urls = typeof b.data.response.resultUrls === 'string' ? JSON.parse(b.data.response.resultUrls) : b.data.response.resultUrls;
      if (Array.isArray(urls) && urls.length > 0) return urls[0];
    } catch(e) {}
  }
  return null;
}

const imageUrl = extractResultUrl(body);
let caption = postData.short_post || '';

// Caption safety: truncate to 950 chars + close HTML tags
if (caption.length > 950) {
  caption = caption.slice(0, 947) + '...';
}

// Close unclosed HTML tags
const openB = (caption.match(/<b>/gi) || []).length;
const closeB = (caption.match(/<\/b>/gi) || []).length;
const openI = (caption.match(/<i>/gi) || []).length;
const closeI = (caption.match(/<\/i>/gi) || []).length;
const openA = (caption.match(/<a[^>]*>/gi) || []).length;
const closeA = (caption.match(/<\/a>/gi) || []).length;

if (openA > closeA) caption += '</a>'.repeat(openA - closeA);
if (openI > closeI) caption += '</i>'.repeat(openI - closeI);
if (openB > closeB) caption += '</b>'.repeat(openB - closeB);

// Cleanup pending post
delete sd.pendingPosts[postId];

return [{json: {
  hasImage: !!imageUrl,
  imageUrl: imageUrl || '',
  caption,
  chatId: '-1003334820713',
  postId,
  skip: false
}}];

