const item = $input.first().json;

// Check if GPT-4o returned an error
const hasError = !!(item.error || item.statusCode >= 400 || !item.choices);

if (hasError) {
  // Pass through articles text for fallback
  const articlesText = $('Фильтр').first()?.json?.articlesText || '';
  return [{json: {gptError: true, articlesText, errorDetail: item.error || item.statusMessage || 'Unknown error'}}];
}

// GPT-4o succeeded — pass through
return [{json: {...item, gptError: false}}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.sentLinks) staticData.sentLinks = {};

// Load links from Google Sheets
const now = Date.now();
const sevenDaysMs = 7 * 24 * 60 * 60 * 1000;

try {
  const sheetRows = $('Load SentLinks').all();
  for (const row of sheetRows) {
    const link = row.json.link || '';
    const sentAt = row.json.sent_at || '';
    if (!link) continue;

    // Parse sent_at timestamp
    let ts = 0;
    if (sentAt) {
      ts = new Date(sentAt).getTime();
      if (isNaN(ts)) ts = now;
    } else {
      ts = now;
    }

    // Only keep links from last 7 days
    if (now - ts <= sevenDaysMs) {
      if (!staticData.sentLinks[link]) {
        staticData.sentLinks[link] = ts;
      }
    }
  }
} catch(e) {
  // Sheets might be empty or fail — continue with staticData only
}

// Pass through RSS items from Merge Финал
const rssItems = $('Merge Финал').all();
return rssItems.length > 0 ? rssItems : [];

// Get the link from the callback data
